  // Helper: format time as AM/PM
  const fmtHora = (h) => {
    if(!h) return "";
    const [hh,mm] = h.split(":");
    const hour = parseInt(hh,10);
    const ampm = hour>=12?"PM":"AM";
    const h12 = hour%12||12;
    return `${h12}:${mm} ${ampm}`;
  };

