  function actualizarReporte(id, cambios) {
    const updated = reportes.map(r => r.id === id ? {...r, ...cambios} : r);
    setReportes(updated);
    const rep = updated.find(r => r.id === id);
    setSelReporte(rep);
    addToast("Reporte actualizado");
    pushNotif(`Reporte de ${rep?.ph} actualizado`, "📋");
    // Sync a Supabase
    if(dbOnline && typeof id === "number") {
      const dbC = {};
      if(cambios.aprobadoPorIng!==undefined) dbC.aprobado_por_ing = cambios.aprobadoPorIng;
      if(cambios.fechaAprobacion) dbC.fecha_aprobacion = cambios.fechaAprobacion;
      if(cambios.comentarioIng!==undefined) dbC.comentario_ing = cambios.comentarioIng;
      if(cambios.firmaDigital) dbC.firma_digital = cambios.firmaDigital;
      if(cambios.estadoRep) dbC.estado_rep = cambios.estadoRep;
    if(cambios.atendido !== undefined) dbC.atendido = cambios.atendido;
    if(cambios.fechaAtendido) dbC.fecha_atendido = cambios.fechaAtendido;
      if(Object.keys(dbC).length) supa.patch("reportes", id, dbC).catch(()=>{});
    }
  }

  // ── Canvas de firma digital ──────────────────────────────────────────────
  const firmaStart = (e) => {
    setFirmaDrawing(true);
    const rect = firmaRef.current.getBoundingClientRect();
    const x = (e.clientX||e.touches?.[0]?.clientX||0) - rect.left;
    const y = (e.clientY||e.touches?.[0]?.clientY||0) - rect.top;
    firmaLastPos.current = {x,y};
  };
  const firmaDraw = (e) => {
    if(!firmaDrawing||!firmaRef.current) return;
    e.preventDefault();
    const rect = firmaRef.current.getBoundingClientRect();
    const x = (e.clientX||e.touches?.[0]?.clientX||0) - rect.left;
    const y = (e.clientY||e.touches?.[0]?.clientY||0) - rect.top;
    const ctx = firmaRef.current.getContext("2d");
    ctx.strokeStyle = "#0D1726"; ctx.lineWidth = 2; ctx.lineCap = "round";
    ctx.beginPath();
    ctx.moveTo(firmaLastPos.current.x, firmaLastPos.current.y);
    ctx.lineTo(x, y);
    ctx.stroke();
    firmaLastPos.current = {x,y};
  };
  const firmaEnd = () => {
    setFirmaDrawing(false);
    if(firmaRef.current) setFirmaCanvas(firmaRef.current.toDataURL());
  };
  const firmaClear = () => {
    if(firmaRef.current){
      const ctx = firmaRef.current.getContext("2d");
      ctx.clearRect(0,0,firmaRef.current.width,firmaRef.current.height);
    }
    setFirmaCanvas(null);
  };

